from flask import Flask, request
import pandas as pd
import tensorflow as tf
from tensorflow import keras
from sklearn.model_selection import train_test_split
import os

app = Flask(__name__)
model = None

def create_model():
    model = keras.Sequential([
        keras.layers.Flatten(input_shape=(28, 28)),
        keras.layers.Dense(128, activation='relu'),
        keras.layers.Dense(10, activation='softmax')
    ])
    model.compile(optimizer='adam', loss='sparse_categorical_crossentropy', metrics=['accuracy'])
    return model

@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return 'No file part', 400
    file = request.files['file']
    if file.filename == '':
        return 'No selected file', 400
    if file:
        file.save(os.path.join('uploads', file.filename))
        return 'File uploaded successfully', 200

@app.route('/train', methods=['POST'])
def train_model():
    global model
    data_files = os.listdir('uploads')
    data = pd.concat([pd.read_csv(os.path.join('uploads', f)) for f in data_files])
    
    X = data.iloc[:, :-1].values
    y = data.iloc[:, -1].values
    X_train, X_test, y_train, y_test = train_test_split(X, y, test_size=0.2)
    
    model = create_model()
    model.fit(X_train, y_train, epochs=5)
    
    test_loss, test_acc = model.evaluate(X_test, y_test)
    return f'Model trained with accuracy: {test_acc}', 200

@app.route('/predict', methods=['POST'])
def predict():
    if model is None:
        return 'Model not trained', 400
    img = request.files['image']
    img.save('temp_image.png')
    img = keras.preprocessing.image.load_img('temp_image.png', target_size=(28, 28))
    img = keras.preprocessing.image.img_to_array(img) / 255.0
    img = img.reshape(1, 28, 28)
    predictions = model.predict(img)
    return f'Predicted class: {predictions.argmax()}', 200

if __name__ == '__main__':
    os.makedirs('uploads', exist_ok=True)
    app.run(debug=True)